PAM_COMMON_AUTH="/etc/pam.d/common-auth"
PAM_COMMON_ACCOUNT="/etc/pam.d/common-account"
PAM_D_COMMON_AUTH="/etc/pam.d/common-auth"
PAM_D_COMMON_ACCOUNT="/etc/pam.d/common-account"
FAILLock_CONF="/etc/security/faillock.conf"

backup_file() {
  local f="$1"
  if [[ -f "$f" && ! -f "${f}.bak" ]]; then
    cp -a "$f" "${f}.bak"
  fi
}

ensure_line_in_file() {
  local file="$1"
  local line="$2"
  grep -Fxq -- "$line" "$file" 2>/dev/null || printf '%s\n' "$line" >> "$file"
}

replace_or_add_block() {
  local file="$1"
  local pattern="$2"
  local replacement="$3"
  if grep -Eq "$pattern" "$file"; then
    sed -i -E "s|$pattern|$replacement|" "$file"
  else
    printf '%s\n' "$replacement" >> "$file"
  fi
}

mkdir -p /etc/security

backup_file "$FAILLock_CONF"
touch "$FAILLock_CONF"

tmp_conf="$(mktemp)"
awk '
BEGIN {
  seen_deny=0; seen_unlock=0; seen_fail_interval=0; seen_even_deny_root=0; seen_audit=0
}
{
  if ($0 ~ /^[[:space:]]*#/ || $0 ~ /^[[:space:]]*$/) { print; next }
  if ($1 == "deny") { print "deny = 5"; seen_deny=1; next }
  if ($1 == "unlock_time") { print "unlock_time = 900"; seen_unlock=1; next }
  if ($1 == "fail_interval") { print "fail_interval = 900"; seen_fail_interval=1; next }
