  if ($1 == "audit") { print "audit"; seen_audit=1; next }
  print
}
END {
  if (!seen_deny) print "deny = 5"
  if (!seen_unlock) print "unlock_time = 900"
  if (!seen_fail_interval) print "fail_interval = 900"
  if (!seen_even_deny_root) print "even_deny_root"
  if (!seen_audit) print "audit"
}' "$FAILLock_CONF" > "$tmp_conf"
cat "$tmp_conf" > "$FAILLock_CONF"
rm -f "$tmp_conf"

for f in "$PAM_COMMON_AUTH" "$PAM_COMMON_ACCOUNT"; do
  [[ -f "$f" ]] || touch "$f"
  backup_file "$f"
done

tmp_auth="$(mktemp)"
awk '
BEGIN { inserted_pre=0; inserted_post=0 }
{
  if ($0 ~ /^[[:space:]]*auth[[:space:]]+required[[:space:]]+pam_faillock\.so[[:space:]]+preauth/) { inserted_pre=1 }
  if ($0 ~ /^[[:space:]]*auth[[:space:]]+required[[:space:]]+pam_faillock\.so[[:space:]]+authfail/) { inserted_post=1 }
