      inserted_pre=1
    }
    print
    if (!inserted_post) {
      print "auth    [default=die]                   pam_faillock.so authfail audit deny=5 unlock_time=900 fail_interval=900"
      inserted_post=1
    }
    next
  }
  if ($0 ~ /^[[:space:]]*auth[[:space:]]+\[success=1 default=ignore\][[:space:]]+pam_unix\.so/) {
    print
    if (!inserted_post) {
      print "auth    [default=die]                   pam_faillock.so authfail audit deny=5 unlock_time=900 fail_interval=900"
      inserted_post=1
    }
    next
  }
  print
}
