  if (!inserted_pre) print "auth    required                        pam_faillock.so preauth silent audit deny=5 unlock_time=900 fail_interval=900"
  if (!inserted_post) print "auth    [default=die]                   pam_faillock.so authfail audit deny=5 unlock_time=900 fail_interval=900"
}' "$PAM_COMMON_AUTH" > "$tmp_auth"
cat "$tmp_auth" > "$PAM_COMMON_AUTH"
rm -f "$tmp_auth"

tmp_account="$(mktemp)"
awk '
BEGIN { inserted=0 }
{
  if ($0 ~ /^[[:space:]]*account[[:space:]]+required[[:space:]]+pam_faillock\.so/) { inserted=1 }
}
{
  if ($0 ~ /^[[:space:]]*account[[:space:]]+required[[:space:]]+pam_unix\.so/) {
    print
