cat "$tmp_account" > "$PAM_COMMON_ACCOUNT"
rm -f "$tmp_account"

chmod 0644 "$FAILLock_CONF" "$PAM_COMMON_AUTH" "$PAM_COMMON_ACCOUNT"

if command -v pam-auth-update >/dev/null 2>&1; then
  pam-auth-update --package --enable faillock >/dev/null 2>&1 || true
